import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Creating a dynamic buffer using StringBuilder
        StringBuilder buffer = new StringBuilder(10);

        // Copying the user input into the buffer with bounds checking
        for (int i = 0; i < Math.min(name.length(), 10); i++) {
            buffer.append(name.charAt(i));
        }

        // Accessing elements within the bounds of the buffer
        System.out.println(buffer.toString());
    }
}

